n wrapper\n    \n    return decorator\n\n\ndef invalidate_cache(keys: List[str]):\n    \"\"\"\n    Decorator to invalidate cache keys after function execution.\n    \n    Args:\n        keys: List of cache key patterns to delete\n               Use {arg_name} placeholders for function arguments\n    \"\"\"\n    def decorator(func: Callable):\n        @functools.wraps(func)\n        async def wrapper(self, *args, **kwargs):\n            # Execute the function first\n            result = await func(self, *args, **kwargs)\n            \n            # Skip cache invalidation if no Redis client\n            if not hasattr(self, 'cache') or self.cache is None:\n                return result\n            \n            # Build actual cache keys from patterns\n            cache_keys_to_delete = []\n            for key_pattern in keys:\n                # Replace placeholders with actual values\n                cache_key = key_pattern\n                \n                # Replace {arg_name} placeholders\n                for i, arg in enumerate(args):\n                    cache_key = cache_key.replace(f\"{{{i}}}\", str(arg))\n                \n                # Replace keyword argument placeholders\n                for arg_name, arg_value in kwargs.items():\n                    if arg_value is not None:\n                        cache_key = cache_key.replace(f\"{{{arg_name}}}\", str(arg_value))\n                \n                cache_keys_to_delete.append(cache_key)\n            \n            # Delete cache keys\n            try:\n                for key in cache_keys_to_delete:\n                    await self.cache.delete(key)\n            except Exception:\n                # Silently fail on cache deletion errors\n                pass\n            \n            return result\n        \n        return wrapper\n    \n    return decorator\n\n\ndef get_cache_key(prefix: str, **kwargs) -> str:\n    \"\"\"\n    Helper to generate consistent cache keys.\n    \"\"\"\n    if not kwargs:\n        return prefix\n    \n    sorted_items = sorted(kwargs.items())\n    key_parts = [prefix]\n    for k, v in sorted_items:\n        if v is not None:\n            key_parts.append(f\"{k}:{v}\")\n    \n    return \":\".join(key_parts)"
